import math

sigma = 0.115
T = 0.5
F = 1.0

def Phi(x):
    return 0.5 * (1 + math.erf(x / math.sqrt(2)))

def lognormal_cdf(K):
    z = (math.log(K / F) + 0.5 * sigma * sigma * T) / (sigma * math.sqrt(T))
    return Phi(z)

p = lognormal_cdf(1.3) - lognormal_cdf(0.7)
